# ============================================================
#  M++ Instalador v4.2 — Motor Nativo C (engine.exe embutida)
#  Requer: Python 3.8+  |  pip install customtkinter
# ============================================================

import os, sys, ctypes, subprocess, base64, shutil, tempfile
import customtkinter as ctk
from tkinter import messagebox

# ── Base64 do mpp.exe (Windows x64, compilado com mingw-w64) ──
ENGINE = ""

INSTALL_DIR  = r"C:\MPlusPlus"
BIN_DIR      = os.path.join(INSTALL_DIR, "bin")
EXE_PATH     = os.path.join(BIN_DIR, "mpp.exe")
BAT_PATH     = os.path.join(BIN_DIR, "mpp.bat")

STDLIB_DIR   = os.path.join(INSTALL_DIR, "stdlib")
DOCS_DIR     = os.path.join(INSTALL_DIR, "docs")

DESINSTALAR  = os.path.join(INSTALL_DIR, "desinstalar.bat")

# ── Verifica / eleva privilégios ────────────────────────────
def is_admin():
    try:    return ctypes.windll.shell32.IsUserAnAdmin()
    except: return False

def elevar():
    ctypes.windll.shell32.ShellExecuteW(
        None, "runas", sys.executable, " ".join(sys.argv), None, 1)
    sys.exit()

# ── Adiciona ao PATH do sistema ──────────────────────────────
def add_to_path(pasta):
    import winreg
    key = winreg.OpenKey(
        winreg.HKEY_LOCAL_MACHINE,
        r"SYSTEM\CurrentControlSet\Control\Session Manager\Environment",
        0, winreg.KEY_READ | winreg.KEY_WRITE)
    try:
        path_val, _ = winreg.QueryValueEx(key, "Path")
    except FileNotFoundError:
        path_val = ""
    if pasta.lower() not in path_val.lower():
        novo = path_val.rstrip(";") + ";" + pasta
        winreg.SetValueEx(key, "Path", 0, winreg.REG_EXPAND_SZ, novo)
    winreg.CloseKey(key)
    # Notifica o sistema
    HWND_BROADCAST = 0xFFFF
    WM_SETTINGCHANGE = 0x001A
    ctypes.windll.user32.SendMessageTimeoutW(
        HWND_BROADCAST, WM_SETTINGCHANGE, 0, "Environment", 2, 5000, None)

# ── Registra .mpp no Windows ────────────────────────────────
def registrar_extensao():
    import winreg
    # .mpp → MPlusPlus.Script
    k1 = winreg.CreateKey(winreg.HKEY_CLASSES_ROOT, ".mpp")
    winreg.SetValueEx(k1, "", 0, winreg.REG_SZ, "MPlusPlus.Script")
    winreg.CloseKey(k1)
    # Descrição
    k2 = winreg.CreateKey(winreg.HKEY_CLASSES_ROOT, "MPlusPlus.Script")
    winreg.SetValueEx(k2, "", 0, winreg.REG_SZ, "M++ Script")
    winreg.CloseKey(k2)
    # Comando
    cmd_key = winreg.CreateKey(
        winreg.HKEY_CLASSES_ROOT,
        r"MPlusPlus.Script\shell\open\command")
    winreg.SetValueEx(cmd_key, "", 0, winreg.REG_SZ,
                      f'"{EXE_PATH}" "%1"')
    winreg.CloseKey(cmd_key)

# ── Cria desinstalador ───────────────────────────────────────
def criar_desinstalador():
    conteudo = f"""@echo off
echo Desinstalando M++...
rd /s /q "{INSTALL_DIR}"
reg delete "HKEY_CLASSES_ROOT\.mpp" /f >nul 2>&1
reg delete "HKEY_CLASSES_ROOT\MPlusPlus.Script" /f >nul 2>&1
echo M++ desinstalado com sucesso!
pause
"""
    with open(DESINSTALAR, "w", encoding="utf-8") as f:
        f.write(conteudo)

# ── Cria hello.mpp de exemplo ────────────────────────────────
def criar_exemplo():
    exemplo = os.path.join(INSTALL_DIR, "exemplo.mpp")
    conteudo = '''// exemplo.mpp — Seu primeiro programa em M++
SAY.IT"{COR:BCIANO}================================{RESET}"
SAY.IT"{COR:BBRANCO}   Bem-vindo ao M++ v4.0!     {RESET}"
SAY.IT"{COR:BCIANO}================================{RESET}"

SET nome = "Mundo"
SAY.IT"Olá, {nome}!"

INPUT usuario "Qual é o seu nome?"
SAY.IT"{COR:BVERDE}Olá, {usuario}! M++ instalado com sucesso!{RESET}"

FOR i FROM 1 TO 5 {
    SAY.IT"  Linha {i} — M++ rodando!"
FIM

SAY.IT"{COR:AMARELO}Tudo certo! Execute: mpp arquivo.mpp{RESET}"
'''
    with open(exemplo, "w", encoding="utf-8") as f:
        f.write(conteudo)

# ── Instalação principal ────────────────────────────────────
def instalar(log_callback):
    try:
        # 1. Cria pastas
        log_callback("📁 Criando diretórios...")
        for d in [INSTALL_DIR, BIN_DIR, STDLIB_DIR, DOCS_DIR]:
            os.makedirs(d, exist_ok=True)

        # 2. Decodifica e salva mpp.exe
        log_callback("🔧 Extraindo motor nativo (engine C)...")
        exe_data = base64.b64decode(ENGINE)
        with open(EXE_PATH, "wb") as f:
            f.write(exe_data)
        log_callback(f"✅ mpp.exe salvo em {EXE_PATH}")

        # 3. Cria mpp.bat (wrapper para PATH)
        log_callback("📄 Criando mpp.bat...")
        with open(BAT_PATH, "w") as f:
            f.write(f'@echo off\n"{EXE_PATH}" %*\n')

        # 4. PATH
        log_callback("🔗 Adicionando ao PATH do sistema...")
        add_to_path(BIN_DIR)

        # 5. Registra .mpp
        log_callback("📌 Registrando extensão .mpp...")
        registrar_extensao()

        # 6. Desinstalador
        log_callback("🗑️  Criando desinstalador...")
        criar_desinstalador()

        # 7. Exemplo
        log_callback("📝 Criando exemplo.mpp...")
        criar_exemplo()

        log_callback("")
        log_callback("🎉 M++ v4.0 instalado com sucesso!")
        log_callback(f"   Caminho: {EXE_PATH}")
        log_callback("   Abra um NOVO terminal e digite: mpp --versao")
        return True

    except Exception as e:
        log_callback(f"❌ Erro: {e}")
        return False

# ── Interface Gráfica ────────────────────────────────────────
class InstaladorApp(ctk.CTk):
    def __init__(self):
        super().__init__()
        ctk.set_appearance_mode("dark")
        ctk.set_default_color_theme("blue")

        self.title("M++ Instalador v4.2 — Motor Nativo C")
        self.geometry("620x520")
        self.resizable(False, False)

        # Título
        ctk.CTkLabel(self, text="M++", font=("Consolas", 48, "bold"),
                     text_color="#FFD700").pack(pady=(20, 0))
        ctk.CTkLabel(self, text="Linguagem de Programação — v4.0 Engine C",
                     font=("Consolas", 13), text_color="#AAAAAA").pack()
        ctk.CTkLabel(self, text="Motor nativo compilado com GCC/MinGW-w64 x64",
                     font=("Consolas", 11), text_color="#888888").pack(pady=(0, 10))

        # Info
        frame_info = ctk.CTkFrame(self, corner_radius=10)
        frame_info.pack(fill="x", padx=20, pady=5)
        infos = [
            ("📁 Destino",     r"C:\MPlusPlus\bin\mpp.exe"),
            ("⚡ Motor",       "C nativo (PE32+ x64, ~345KB)"),
            ("🔤 Extensão",    ".mpp registrada no Windows"),
            ("🗑️  Desinstalar", r"C:\MPlusPlus\desinstalar.bat"),
        ]
        for label, val in infos:
            row = ctk.CTkFrame(frame_info, fg_color="transparent")
            row.pack(fill="x", padx=10, pady=2)
            ctk.CTkLabel(row, text=label, width=110,
                         font=("Consolas", 11, "bold"),
                         anchor="w").pack(side="left")
            ctk.CTkLabel(row, text=val,
                         font=("Consolas", 11),
                         text_color="#66AAFF",
                         anchor="w").pack(side="left")

        # Log
        self.log_box = ctk.CTkTextbox(self, height=160,
                                      font=("Consolas", 11),
                                      fg_color="#0a0a0a",
                                      text_color="#00FF88")
        self.log_box.pack(fill="x", padx=20, pady=10)
        self.log_box.configure(state="disabled")

        # Botão instalar
        self.btn = ctk.CTkButton(
            self, text="⚡  INSTALAR M++ v4.0",
            font=("Consolas", 14, "bold"),
            height=45, corner_radius=8,
            fg_color="#FFD700", hover_color="#FFA500",
            text_color="#000000",
            command=self.iniciar_instalacao)
        self.btn.pack(pady=5, padx=20, fill="x")

        # Rodapé
        ctk.CTkLabel(self, text="M++ é open source | Motor em ANSI C puro",
                     font=("Consolas", 10),
                     text_color="#555555").pack(pady=(5, 10))

    def log(self, msg):
        self.log_box.configure(state="normal")
        self.log_box.insert("end", msg + "\n")
        self.log_box.see("end")
        self.log_box.configure(state="disabled")
        self.update()

    def iniciar_instalacao(self):
        self.btn.configure(state="disabled", text="⏳ Instalando...")
        self.after(100, self._instalar)

    def _instalar(self):
        ok = instalar(self.log)
        if ok:
            self.btn.configure(
                text="✅ Instalado! Abra um novo terminal",
                fg_color="#00AA44",
                hover_color="#00AA44")
            messagebox.showinfo(
                "M++ Instalado!",
                "M++ v4.0 (motor C nativo) instalado com sucesso!\n\n"
                "Abra um NOVO terminal e teste:\n"
                "  mpp --versao\n"
                "  mpp exemplo.mpp\n\n"
                f"Arquivos em: {INSTALL_DIR}")
        else:
            self.btn.configure(state="normal", text="⚡  INSTALAR M++ v4.0")

# ── Entry point ──────────────────────────────────────────────
if __name__ == "__main__":
    if not is_admin():
        elevar()
    app = InstaladorApp()
    app.mainloop()
